/**
 * Updates the context object in real-time after language selection.
 * This ensures the subsequent Welcome Message can be localized 
 * immediately using the choice we just saved to the database.
 */

// 1. Extract language identifier from the button payload (e.g., 'lang_en' -> 'en')
const rawInput = $node["Strict Entry (Contract)"].json.input_text || "";
const resolvedLanguage = rawInput.replace('lang_', '');

// 2. Retrieve the context passed from the Middleware (SW-0)
const context = $node["Strict Entry (Contract)"].json.context || {};

// 3. Patch the identity and state
context.language = resolvedLanguage;
context.is_new_user = false;

return {
  ...$input.item.json,
  context: context
};

